"use strict";(self.webpackChunkpendle_documentation=self.webpackChunkpendle_documentation||[]).push([[6344],{9467:e=>{e.exports=JSON.parse('{"version":{"pluginId":"boros-dev","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"borosSidebar":[{"type":"link","label":"Introduction","href":"/boros-dev/","customProps":{"icon":"auto_stories"},"docId":"Introduction","unlisted":false},{"type":"link","label":"Lite Paper","href":"/boros-dev/LitePaper","customProps":{"icon":"article"},"docId":"LitePaper","unlisted":false},{"type":"link","label":"High Level Architecture","href":"/boros-dev/HighLevelArchitecture","customProps":{"icon":"architecture"},"docId":"HighLevelArchitecture","unlisted":false},{"type":"category","label":"Mechanics","customProps":{"icon":"settings"},"items":[{"type":"link","label":"Order Book","href":"/boros-dev/Mechanics/OrderBook","customProps":{"icon":"candlestick_chart"},"docId":"Mechanics/OrderBook","unlisted":false},{"type":"link","label":"AMM","href":"/boros-dev/Mechanics/AMM","customProps":{"icon":"waves"},"docId":"Mechanics/AMM","unlisted":false},{"type":"link","label":"Margin","href":"/boros-dev/Mechanics/Margin","customProps":{"icon":"account_balance"},"docId":"Mechanics/Margin","unlisted":false},{"type":"link","label":"Settlement","href":"/boros-dev/Mechanics/Settlement","customProps":{"icon":"task_alt"},"docId":"Mechanics/Settlement","unlisted":false},{"type":"link","label":"Fees","href":"/boros-dev/Mechanics/Fees","customProps":{"icon":"payments"},"docId":"Mechanics/Fees","unlisted":false},{"type":"link","label":"Incentives","href":"/boros-dev/Mechanics/Incentives","customProps":{"icon":"redeem"},"docId":"Mechanics/Incentives","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Contracts","customProps":{"icon":"description"},"items":[{"type":"link","label":"Router","href":"/boros-dev/Contracts/Router","customProps":{"icon":"alt_route"},"docId":"Contracts/Router","unlisted":false},{"type":"link","label":"MarketHub","href":"/boros-dev/Contracts/MarketHub","customProps":{"icon":"storefront"},"docId":"Contracts/MarketHub","unlisted":false},{"type":"link","label":"Market","href":"/boros-dev/Contracts/Market","customProps":{"icon":"trending_up"},"docId":"Contracts/Market","unlisted":false},{"type":"link","label":"Custom Types","href":"/boros-dev/Contracts/CustomTypes","customProps":{"icon":"data_object"},"docId":"Contracts/CustomTypes","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Backend Integration","customProps":{"icon":"integration_instructions"},"items":[{"type":"link","label":"Overview","href":"/boros-dev/Backend/overview","customProps":{"icon":"info"},"docId":"Backend/overview","unlisted":false},{"type":"link","label":"Glossary","href":"/boros-dev/Backend/glossary","customProps":{"icon":"library_books"},"docId":"Backend/glossary","unlisted":false},{"type":"link","label":"Agent","href":"/boros-dev/Backend/agent","customProps":{"icon":"smart_toy"},"docId":"Backend/agent","unlisted":false},{"type":"link","label":"SDK (TypeScript)","href":"/boros-dev/Backend/sdk","customProps":{"icon":"code"},"docId":"Backend/sdk","unlisted":false},{"type":"link","label":"API","href":"/boros-dev/Backend/api","customProps":{"icon":"api"},"docId":"Backend/api","unlisted":false},{"type":"link","label":"WebSocket","href":"/boros-dev/Backend/websocket","customProps":{"icon":"wifi"},"docId":"Backend/websocket","unlisted":false},{"type":"link","label":"Historical Data","href":"/boros-dev/Backend/historical-data","customProps":{"icon":"history"},"docId":"Backend/historical-data","unlisted":false},{"type":"link","label":"Indicators","href":"/boros-dev/Backend/indicators","customProps":{"icon":"insights"},"docId":"Backend/indicators","unlisted":false},{"type":"link","label":"Computing Units","href":"/boros-dev/Backend/computing-units","customProps":{"icon":"speed"},"docId":"Backend/computing-units","unlisted":false},{"type":"link","label":"Best Practices","href":"/boros-dev/Backend/best-practices","customProps":{"icon":"star"},"docId":"Backend/best-practices","unlisted":false},{"type":"link","label":"Bot Quickstart","href":"/boros-dev/Backend/bot-quickstart","customProps":{"icon":"rocket_launch"},"docId":"Backend/bot-quickstart","unlisted":false},{"type":"link","label":"API Migration","href":"/boros-dev/Backend/api-migration","customProps":{"icon":"swap_horiz"},"docId":"Backend/api-migration","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"link","label":"FAQ","href":"/boros-dev/FAQ","customProps":{"icon":"help"},"docId":"FAQ","unlisted":false}]},"docs":{"Backend/agent":{"id":"Backend/agent","title":"Agent Trading","description":"Overview","sidebar":"borosSidebar"},"Backend/api":{"id":"Backend/api","title":"Boros Open API","description":"This guide walks you through integrating with the Boros trading platform via the REST API. For exact request/response schemas and parameter details, see the interactive API docs.","sidebar":"borosSidebar"},"Backend/api-migration":{"id":"Backend/api-migration","title":"API Migration","description":"The legacy https//api-boros.pendle.finance/apis/ before then.","sidebar":"borosSidebar"},"Backend/best-practices":{"id":"Backend/best-practices","title":"Boros API Best Practices","description":"This guide provides recommendations and common patterns for integrating with the Boros API efficiently.","sidebar":"borosSidebar"},"Backend/bot-quickstart":{"id":"Backend/bot-quickstart","title":"Bot Quickstart \u2014 Zero to Functional Grid Bot","description":"This page walks you from a freshly funded Boros root account to a running grid bot that places, cancels, and refills real limit orders on Arbitrum mainnet. The bot is built with @pendle/boros-sdk-public \u2014 a TypeScript wrapper that handles calldata building, EIP-712 signing, and Send Txs Bot dispatch on your behalf.","sidebar":"borosSidebar"},"Backend/computing-units":{"id":"Backend/computing-units","title":"Computing Units","description":"Every Open API endpoint advertises a per-call cost called a Computing Unit (CU). CU is how Pendle meters the work each request does and enforces fair-use against high-frequency consumers.","sidebar":"borosSidebar"},"Backend/glossary":{"id":"Backend/glossary","title":"Glossary","description":"Quick reference for key terms used in the Boros API. For portfolio concepts (Rate Sensitivity, Daily Volatility, margin, PnL, liquidation), see the Boros User Glossary.","sidebar":"borosSidebar"},"Backend/historical-data":{"id":"Backend/historical-data","title":"Historical Data","description":"Historical market data exports for Pendle Boros on Arbitrum.","sidebar":"borosSidebar"},"Backend/indicators":{"id":"Backend/indicators","title":"Indicators","description":"The /v1/indicators endpoint exposes a unified time-series API for the off-chain market analytics that power the Boros UI\'s chart panel. Every indicator is identified by a short letter code and bucketed at one of four timeframes.","sidebar":"borosSidebar"},"Backend/overview":{"id":"Backend/overview","title":"Backend Integration","description":"Backend integration means interacting with Boros through its REST API and TypeScript SDK rather than calling contracts directly. This is the recommended path for most integrators: the API handles calldata generation, signature encoding, and on-chain submission, so you can build trading workflows without managing ABI encoding or gas mechanics yourself.","sidebar":"borosSidebar"},"Backend/sdk":{"id":"Backend/sdk","title":"SDK (TypeScript)","description":"@pendle/boros-sdk-public is a TypeScript wrapper around the Boros Open API and Send Txs Bot. It removes the boilerplate of building calldata, EIP-712 signing, and dispatching transactions. If you trade from Node, this is the recommended path.","sidebar":"borosSidebar"},"Backend/websocket":{"id":"Backend/websocket","title":"Boros WebSocket","description":"This guide explains how to directly connect to Boros\'s WebSocket service using Socket.IO client.","sidebar":"borosSidebar"},"Contracts/CustomTypes":{"id":"Contracts/CustomTypes","title":"Custom Types","description":"Boros heavily uses Solidity user-defined value types for gas optimization and type safety. These types use bit-packing to minimize storage costs and provide efficient operations on the EVM.","sidebar":"borosSidebar"},"Contracts/Market":{"id":"Contracts/Market","title":"Market View Functions","description":"The REST API provides all market data (positions, order books, margins) with up-to-date settlement applied. Direct contract calls return unsettled data and require manual settlement triggers. Use the API unless you have a specific need for on-chain reads.","sidebar":"borosSidebar"},"Contracts/MarketHub":{"id":"Contracts/MarketHub","title":"MarketHub View Functions","description":"The REST API exposes the same data (balances, withdrawals, entered markets) with proper settlement handling. Direct contract calls return unsettled data. Use the API unless you have a specific need for on-chain reads.","sidebar":"borosSidebar"},"Contracts/Router":{"id":"Contracts/Router","title":"Router Integration Guide","description":"Interacting with Boros contracts directly is not recommended for most use cases. The REST API and SDK handle authentication, calldata encoding, and transaction submission for you. Direct contract interaction is error-prone and may break if contract addresses or ABIs change. The information below is provided as a reference for advanced integrators only.","sidebar":"borosSidebar"},"FAQ":{"id":"FAQ","title":"Frequently Asked Questions","description":"Getting Started","sidebar":"borosSidebar"},"HighLevelArchitecture":{"id":"HighLevelArchitecture","title":"High Level Architecture","description":"For most integrations, interact with Boros through the REST API and SDK rather than calling contracts directly. The API handles calldata encoding, settlement, and transaction submission. The contract details below are provided as an architectural reference.","sidebar":"borosSidebar"},"Introduction":{"id":"Introduction","title":"Boros Developer Documentation","description":"Boros is an on-chain interest rate swap (IRS) trading platform by Pendle, deployed on Arbitrum. It enables users to take leveraged long or short positions on variable interest rates \u2014 starting with funding rates \u2014 through a hybrid central limit order book (CLOB) and AMM architecture. These docs are for developers integrating with Boros programmatically, whether through the REST API and SDK, direct smart contract calls, or both.","sidebar":"borosSidebar"},"LitePaper":{"id":"LitePaper","title":"Boros Lite Paper","description":"This document outlines how Boros works in a more high level and user-centric manner. Exact formal definitions and formulas can be found in the whitepaper.","sidebar":"borosSidebar"},"Mechanics/AMM":{"id":"Mechanics/AMM","title":"AMM","description":"Boros pairs each market with an optional Automated Market Maker (AMM) that provides continuous liquidity alongside the central limit order book. The AMM is implemented as a normal MarketAcc with no special powers \u2014 its only privilege is that it can OTC-swap with users when the Router routes through it. This page explains how the AMM is priced, how add/remove-liquidity works, and how it composes with the order book.","sidebar":"borosSidebar"},"Mechanics/Fees":{"id":"Mechanics/Fees","title":"Fees","description":"Boros charges various fees to maintain protocol sustainability. This section outlines all fee types that users should be aware of when trading on the platform.","sidebar":"borosSidebar"},"Mechanics/Incentives":{"id":"Mechanics/Incentives","title":"Incentives","description":"Boros runs PENDLE-denominated reward programs to bootstrap liquidity. There are two distinct incentive surfaces \u2014 one for order-book makers and one for AMM liquidity providers. Both can be queried through the Open API; this page describes how each is computed and where to read it.","sidebar":"borosSidebar"},"Mechanics/Margin":{"id":"Mechanics/Margin","title":"Margin","description":"Similar to other derivative exchanges, Boros supports both cross margin and isolated margin modes:","sidebar":"borosSidebar"},"Mechanics/OrderBook":{"id":"Mechanics/OrderBook","title":"Central Limit Order Book","description":"Boros implements a gas-optimized central limit order book (CLOB) specifically designed for the EVM. The order book architecture minimizes gas costs through lazy settlement and efficient data structures while maintaining the functionality expected from professional trading platforms.","sidebar":"borosSidebar"},"Mechanics/Settlement":{"id":"Mechanics/Settlement","title":"Settlement","description":"In Boros, settlement refers to the position update when a trade happens (e.g., market order placed, limit order filled) and the periodic floating payment.","sidebar":"borosSidebar"}}}}')}}]);